'use client';

import { useState } from 'react';
import styles from './admin.module.css';
import { Users, Calendar, MessageSquare, Shield, Activity, ArrowRight, Settings } from 'lucide-react';
import { useT } from '@/i18n/client';

export default function AdminDashboard() {
    const tAdmin = useT("admin");
    const [activeTab, setActiveTab] = useState('overview');
    const [searchQuery, setSearchQuery] = useState('');
    const [currentPage, setCurrentPage] = useState(1);
    const itemsPerPage = 5;

    // Mock data for Users
    const allUsers = [
        { id: '1', name: 'Anna Andersson', email: 'anna@example.com', role: 'USER', joined: '2024-03-01' },
        { id: '2', name: 'Sarah Chen', email: 'sarah@coach.local', role: 'COACH', joined: '2024-02-15' },
        { id: '3', name: 'John Doe', email: 'john@example.com', role: 'USER', joined: '2024-03-10' },
        { id: '4', name: 'Maria Garcia', email: 'maria@example.com', role: 'USER', joined: '2024-01-20' },
        { id: '5', name: 'David Wilson', email: 'david@example.com', role: 'USER', joined: '2024-03-05' },
        { id: '6', name: 'Emma Lindberg', email: 'emma@example.com', role: 'USER', joined: '2024-03-11' },
        { id: '7', name: 'James Miller', email: 'james@coach.local', role: 'COACH', joined: '2024-01-10' },
        { id: '8', name: 'Sofia Nilsson', email: 'sofia@example.com', role: 'USER', joined: '2024-02-28' },
    ];

    // Mock data for Bookings
    const allBookings = [
        { id: '101', user: 'Anna Andersson', coach: 'Sarah Chen', time: tAdmin('sample.timeTomorrow'), status: 'Confirmed' },
        { id: '102', user: 'David Wilson', coach: 'James Miller', time: 'Today 14:00', status: 'Pending' },
        { id: '103', user: 'Maria Garcia', coach: 'Sarah Chen', time: 'Monday 09:00', status: 'Confirmed' },
        { id: '104', user: 'Emma Lindberg', coach: 'James Miller', time: 'Tuesday 16:30', status: 'Cancelled' },
        { id: '105', user: 'John Doe', coach: 'Sarah Chen', time: 'Wednesday 11:00', status: 'Confirmed' },
        { id: '106', user: 'Sofia Nilsson', coach: 'James Miller', time: 'Thursday 15:00', status: 'Confirmed' },
    ];

    const stats = [
        { label: tAdmin('users'), value: allUsers.length.toString(), icon: Users, color: 'var(--floral-purple)' },
        { label: tAdmin('coaches'), value: allUsers.filter(u => u.role === 'COACH').length.toString(), icon: Shield, color: 'var(--accent-sage)' },
        { label: tAdmin('bookings'), value: allBookings.length.toString(), icon: Calendar, color: 'var(--accent-blue)' },
        { label: tAdmin('messages'), value: '890', icon: MessageSquare, color: 'var(--accent-heart)' },
    ];

    // Filtering logic
    const filteredUsers = allUsers.filter(u =>
        u.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        u.email.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const filteredBookings = allBookings.filter(b =>
        b.user.toLowerCase().includes(searchQuery.toLowerCase()) ||
        b.coach.toLowerCase().includes(searchQuery.toLowerCase())
    );

    // Pagination logic
    const paginate = (items: any[]) => {
        const startIndex = (currentPage - 1) * itemsPerPage;
        return items.slice(startIndex, startIndex + itemsPerPage);
    };

    const totalPagesUsers = Math.ceil(filteredUsers.length / itemsPerPage);
    const totalPagesBookings = Math.ceil(filteredBookings.length / itemsPerPage);

    const handleTabChange = (tab: string) => {
        setActiveTab(tab);
        setSearchQuery('');
        setCurrentPage(1);
    };

    return (
        <div className={styles.wrapper}>
            <aside className={styles.sidebar}>
                <div className={styles.logo}>
                    <img src="/branding/heart.png" alt="" />
                    <span>{tAdmin('title')}</span>
                </div>

                <nav className={styles.nav}>
                    <button className={activeTab === 'overview' ? styles.active : ''} onClick={() => handleTabChange('overview')}>
                        <Activity size={18} /> {tAdmin('overview')}
                    </button>
                    <button className={activeTab === 'users' ? styles.active : ''} onClick={() => handleTabChange('users')}>
                        <Users size={18} /> {tAdmin('users')}
                    </button>
                    <button className={activeTab === 'bookings' ? styles.active : ''} onClick={() => handleTabChange('bookings')}>
                        <Calendar size={18} /> {tAdmin('bookings')}
                    </button>
                    <button className={activeTab === 'settings' ? styles.active : ''} onClick={() => handleTabChange('settings')}>
                        <Settings size={18} /> {tAdmin('settings')}
                    </button>
                </nav>
            </aside>

            <main className={styles.main}>
                {activeTab === 'overview' && (
                    <>
                        <header className={styles.header}>
                            <h2>{tAdmin('platformOverview')}</h2>
                            <div className={styles.userProfile}>
                                <span>admin@supportnetwork.local</span>
                                <div className={styles.avatar}>A</div>
                            </div>
                        </header>

                        <section className={styles.statsGrid}>
                            {stats.map(s => (
                                <div key={s.label} className={styles.statCard}>
                                    <div className={styles.statInfo}>
                                        <p>{s.label}</p>
                                        <h3>{s.value}</h3>
                                    </div>
                                    <div className={styles.statIcon} style={{ background: s.color + '22', color: s.color }}>
                                        <s.icon size={24} />
                                    </div>
                                </div>
                            ))}
                        </section>

                        <section className={styles.content}>
                            <div className={styles.recentActivity}>
                                <div className={styles.sectionHeader}>
                                    <h3>{tAdmin('recentBookings')}</h3>
                                    <button className={styles.viewAll} onClick={() => handleTabChange('bookings')}>{tAdmin('viewAll')} <ArrowRight size={14} /></button>
                                </div>
                                <div className={styles.table}>
                                    <div className={styles.tableRow}>
                                        <div className={styles.tableCell}><strong>{tAdmin('table.user')}</strong></div>
                                        <div className={styles.tableCell}><strong>{tAdmin('table.coach')}</strong></div>
                                        <div className={styles.tableCell}><strong>{tAdmin('table.time')}</strong></div>
                                        <div className={styles.tableCell}><strong>{tAdmin('table.status')}</strong></div>
                                    </div>
                                    {allBookings.slice(0, 3).map(b => (
                                        <div key={b.id} className={styles.tableRow}>
                                            <div className={styles.tableCell}>{b.user}</div>
                                            <div className={styles.tableCell}>{b.coach}</div>
                                            <div className={styles.tableCell}>{b.time}</div>
                                            <div className={styles.tableCell}><span className={`${styles.badge} ${styles[b.status.toLowerCase()]}`}>{tAdmin(`status${b.status}`)}</span></div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </section>
                    </>
                )}

                {activeTab === 'users' && (
                    <section className={styles.content}>
                        <div className={styles.contentHeader}>
                            <h3>{tAdmin('users')}</h3>
                            <div className={styles.searchBar}>
                                <input
                                    type="text"
                                    placeholder={tAdmin('searchUsers') || 'Search users...'}
                                    value={searchQuery}
                                    onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
                                />
                            </div>
                        </div>
                        <div className={styles.table}>
                            <div className={styles.tableRow}>
                                <div className={styles.tableCell}><strong>{tAdmin('table.user')}</strong></div>
                                <div className={styles.tableCell}><strong>Email</strong></div>
                                <div className={styles.tableCell}><strong>Role</strong></div>
                                <div className={styles.tableCell}><strong>Joined</strong></div>
                            </div>
                            {paginate(filteredUsers).map(u => (
                                <div key={u.id} className={styles.tableRow}>
                                    <div className={styles.tableCell}>{u.name}</div>
                                    <div className={styles.tableCell}>{u.email}</div>
                                    <div className={styles.tableCell}>{u.role}</div>
                                    <div className={styles.tableCell}>{u.joined}</div>
                                </div>
                            ))}
                        </div>
                        {totalPagesUsers > 1 && (
                            <div className={styles.pagination}>
                                <button disabled={currentPage === 1} onClick={() => setCurrentPage(p => p - 1)}>Prev</button>
                                <span>Page {currentPage} of {totalPagesUsers}</span>
                                <button disabled={currentPage === totalPagesUsers} onClick={() => setCurrentPage(p => p + 1)}>Next</button>
                            </div>
                        )}
                    </section>
                )}

                {activeTab === 'bookings' && (
                    <section className={styles.content}>
                        <div className={styles.contentHeader}>
                            <h3>{tAdmin('bookings')}</h3>
                            <div className={styles.searchBar}>
                                <input
                                    type="text"
                                    placeholder={tAdmin('searchBookings') || 'Search bookings...'}
                                    value={searchQuery}
                                    onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
                                />
                            </div>
                        </div>
                        <div className={styles.table}>
                            <div className={styles.tableRow}>
                                <div className={styles.tableCell}><strong>{tAdmin('table.user')}</strong></div>
                                <div className={styles.tableCell}><strong>{tAdmin('table.coach')}</strong></div>
                                <div className={styles.tableCell}><strong>{tAdmin('table.time')}</strong></div>
                                <div className={styles.tableCell}><strong>{tAdmin('table.status')}</strong></div>
                            </div>
                            {paginate(filteredBookings).map(b => (
                                <div key={b.id} className={styles.tableRow}>
                                    <div className={styles.tableCell}>{b.user}</div>
                                    <div className={styles.tableCell}>{b.coach}</div>
                                    <div className={styles.tableCell}>{b.time}</div>
                                    <div className={styles.tableCell}><span className={`${styles.badge} ${styles[b.status.toLowerCase()]}`}>{tAdmin(`status${b.status}`)}</span></div>
                                </div>
                            ))}
                        </div>
                        {totalPagesBookings > 1 && (
                            <div className={styles.pagination}>
                                <button disabled={currentPage === 1} onClick={() => setCurrentPage(p => p - 1)}>Prev</button>
                                <span>Page {currentPage} of {totalPagesBookings}</span>
                                <button disabled={currentPage === totalPagesBookings} onClick={() => setCurrentPage(p => p + 1)}>Next</button>
                            </div>
                        )}
                    </section>
                )}

                {activeTab === 'settings' && (
                    <section className={styles.content}>
                        <h3>{tAdmin('settings')}</h3>
                        <div className={styles.settingsGrid}>
                            <div className={styles.settingCard}>
                                <h4>General Settings</h4>
                                <p>View and manage general platform settings.</p>
                                <button className={styles.secondaryBtn}>Toggle Maintenance Mode</button>
                            </div>
                            <div className={styles.settingCard}>
                                <h4>Notifications</h4>
                                <p>Manage email and push notifications settings.</p>
                                <button className={styles.secondaryBtn}>Configure Postmark</button>
                            </div>
                        </div>
                    </section>
                )}
            </main>
        </div>
    );
}
